const setC = (out, ...values) => {
  if (!out) return values;
  for (let i = values.length; i-- > 0; ) out[i] = values[i];
  return out;
};
const setC2 = (out, x, y) => {
  !out && (out = []);
  out[0] = x;
  out[1] = y;
  return out;
};
const setC3 = (out, x, y, z) => {
  !out && (out = []);
  out[0] = x;
  out[1] = y;
  out[2] = z;
  return out;
};
const setC4 = (out, x, y, z, w) => {
  !out && (out = []);
  out[0] = x;
  out[1] = y;
  out[2] = z;
  out[3] = w;
  return out;
};
const setC6 = (out, a, b, c, d, e, f) => {
  !out && (out = []);
  out[0] = a;
  out[1] = b;
  out[2] = c;
  out[3] = d;
  out[4] = e;
  out[5] = f;
  return out;
};
export {
  setC,
  setC2,
  setC3,
  setC4,
  setC6
};
